
import React, { useState } from 'react';
import { Helmet } from 'react-helmet';
import { motion } from 'framer-motion';
import { Phone, Mail, MapPin, Clock } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Label } from '@/components/ui/label';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import Header from '@/components/Header.jsx';
import Footer from '@/components/Footer.jsx';

const ContactPage = () => {
  const [formData, setFormData] = useState({
    fullName: '',
    companyName: '',
    industry: '',
    email: '',
    phone: '',
    message: '',
    hearAbout: '',
  });

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitSuccess, setSubmitSuccess] = useState(false);
  const [submitError, setSubmitError] = useState('');

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleSelectChange = (name, value) => {
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setIsSubmitting(true);
    setSubmitError('');

    try {
      const response = await fetch('https://formspree.io/f/mwvwvwob', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          fullName: formData.fullName,
          companyName: formData.companyName || 'Not provided',
          industry: formData.industry || 'Not provided',
          email: formData.email,
          phoneNumber: formData.phone || 'Not provided',
          message: formData.message,
          hearAboutUs: formData.hearAbout || 'Not provided',
        }),
      });

      if (!response.ok) {
        throw new Error('Submission failed');
      }

      setSubmitSuccess(true);
    } catch (error) {
      setSubmitError('Something went wrong. Please try again or email us directly.');
    } finally {
      setIsSubmitting(false);
    }
  };

  const contactDetails = [
    {
      icon: Phone,
      label: 'Phone',
      value: '+61 (0) 484 311 234',
      href: 'tel:+61484311234',
    },
    {
      icon: Mail,
      label: 'Email',
      value: 'omer.bashir@saizor.com',
      href: 'mailto:omer.bashir@saizor.com',
    },
    {
      icon: MapPin,
      label: 'Location',
      value: 'Perth, Western Australia',
    },
    {
      icon: Clock,
      label: 'Hours',
      value: 'Monday to Friday, 9am to 5pm AWST',
    },
  ];

  return (
    <>
      <Helmet>
        <title>Contact Saizor — Book Your AI Audit Today</title>
        <meta name="description" content="Get in touch with Saizor. Call +61 (0) 484 311 234 or email omer.bashir@saizor.com. Perth-based AI audit experts." />
      </Helmet>

      <Header />

      {/* Hero Section */}
      <section className="section-spacing bg-gradient-to-br from-background via-secondary/20 to-background">
        <div className="max-w-7xl mx-auto container-padding">
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6 }}
            className="max-w-3xl mx-auto text-center"
          >
            <h1 className="text-4xl md:text-5xl lg:text-6xl font-bold leading-tight mb-6" style={{ letterSpacing: '-0.02em' }}>
              Get in touch
            </h1>
            <p className="text-lg md:text-xl text-foreground/80 leading-relaxed">
              Ready to book your AI maturity audit or have questions? We're here to help.
            </p>
          </motion.div>
        </div>
      </section>

      {/* Contact Section */}
      <section className="section-spacing">
        <div className="max-w-7xl mx-auto container-padding">
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
            {/* Contact Details */}
            <motion.div
              initial={{ opacity: 0, x: -20 }}
              whileInView={{ opacity: 1, x: 0 }}
              viewport={{ once: true }}
              transition={{ duration: 0.5 }}
            >
              <h2 className="text-2xl font-bold mb-6">Contact details</h2>
              <div className="space-y-6 mb-8">
                {contactDetails.map((detail, index) => (
                  <div key={index} className="flex items-start gap-4">
                    <div className="w-12 h-12 rounded-xl bg-primary/10 flex items-center justify-center flex-shrink-0">
                      <detail.icon className="w-6 h-6 text-primary" />
                    </div>
                    <div>
                      <p className="text-sm font-medium text-foreground/60 mb-1">{detail.label}</p>
                      {detail.href ? (
                        <a
                          href={detail.href}
                          className="text-foreground hover:text-primary transition-colors duration-200"
                        >
                          {detail.value}
                        </a>
                      ) : (
                        <p className="text-foreground">{detail.value}</p>
                      )}
                    </div>
                  </div>
                ))}
              </div>

              <div className="bg-card rounded-2xl p-6 border border-border">
                <p className="text-sm text-foreground/80 leading-relaxed mb-4">
                  <span className="font-semibold">Prefer to talk?</span> Call us directly on{' '}
                  <a href="tel:+61484311234" className="text-primary hover:underline">
                    +61 (0) 484 311 234
                  </a>
                </p>
                <p className="text-sm text-foreground/80 leading-relaxed">
                  We respond to all enquiries within 1 business day.
                </p>
              </div>
            </motion.div>

            {/* Contact Form */}
            <motion.div
              initial={{ opacity: 0, x: 20 }}
              whileInView={{ opacity: 1, x: 0 }}
              viewport={{ once: true }}
              transition={{ duration: 0.5 }}
            >
              {submitSuccess ? (
                <div className="flex items-center justify-center h-full min-h-[400px]">
                  <div className="bg-card rounded-2xl border border-border p-8 text-center">
                    <p className="text-xl font-semibold text-foreground">
                      Thank you! We will be in touch within 1 business day.
                    </p>
                  </div>
                </div>
              ) : (
              <form onSubmit={handleSubmit} className="space-y-6">
                <div>
                  <Label htmlFor="fullName">Full name *</Label>
                  <Input
                    id="fullName"
                    name="fullName"
                    type="text"
                    value={formData.fullName}
                    onChange={handleChange}
                    required
                    className="mt-2 bg-card text-foreground placeholder:text-muted-foreground"
                    placeholder="Your full name"
                  />
                </div>

                <div>
                  <Label htmlFor="companyName">Company name</Label>
                  <Input
                    id="companyName"
                    name="companyName"
                    type="text"
                    value={formData.companyName}
                    onChange={handleChange}
                    className="mt-2 bg-card text-foreground placeholder:text-muted-foreground"
                    placeholder="Your company"
                  />
                </div>

                <div>
                  <Label htmlFor="industry">Industry</Label>
                  <Select
                    value={formData.industry}
                    onValueChange={(value) => handleSelectChange('industry', value)}
                  >
                    <SelectTrigger className="mt-2 bg-card text-foreground">
                      <SelectValue placeholder="Select your industry" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="healthcare">Healthcare</SelectItem>
                      <SelectItem value="finance">Finance</SelectItem>
                      <SelectItem value="retail">Retail</SelectItem>
                      <SelectItem value="manufacturing">Manufacturing</SelectItem>
                      <SelectItem value="professional-services">Professional Services</SelectItem>
                      <SelectItem value="other">Other</SelectItem>
                    </SelectContent>
                  </Select>
                </div>

                <div>
                  <Label htmlFor="email">Email address *</Label>
                  <Input
                    id="email"
                    name="email"
                    type="email"
                    value={formData.email}
                    onChange={handleChange}
                    required
                    className="mt-2 bg-card text-foreground placeholder:text-muted-foreground"
                    placeholder="your.email@company.com"
                  />
                </div>

                <div>
                  <Label htmlFor="phone">Phone number</Label>
                  <Input
                    id="phone"
                    name="phone"
                    type="tel"
                    value={formData.phone}
                    onChange={handleChange}
                    className="mt-2 bg-card text-foreground placeholder:text-muted-foreground"
                    placeholder="+61 4XX XXX XXX"
                  />
                </div>

                <div>
                  <Label htmlFor="message">Message *</Label>
                  <Textarea
                    id="message"
                    name="message"
                    value={formData.message}
                    onChange={handleChange}
                    required
                    rows={5}
                    className="mt-2 bg-card text-foreground placeholder:text-muted-foreground"
                    placeholder="Tell us about your AI needs or questions..."
                  />
                </div>

                <div>
                  <Label htmlFor="hearAbout">How did you hear about us?</Label>
                  <Select
                    value={formData.hearAbout}
                    onValueChange={(value) => handleSelectChange('hearAbout', value)}
                  >
                    <SelectTrigger className="mt-2 bg-card text-foreground">
                      <SelectValue placeholder="Select an option" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="google">Google</SelectItem>
                      <SelectItem value="linkedin">LinkedIn</SelectItem>
                      <SelectItem value="referral">Referral</SelectItem>
                      <SelectItem value="event">Event</SelectItem>
                      <SelectItem value="other">Other</SelectItem>
                    </SelectContent>
                  </Select>
                </div>

                {submitError && (
                  <p className="text-sm text-destructive">{submitError}</p>
                )}

                <Button
                  type="submit"
                  size="lg"
                  className="w-full transition-all duration-200 active:scale-[0.98]"
                  disabled={isSubmitting}
                >
                  {isSubmitting ? 'Sending...' : 'Send message'}
                </Button>
              </form>
              )}
            </motion.div>
          </div>
        </div>
      </section>

      <Footer />
    </>
  );
};

export default ContactPage;
